        require(elementType == PRIMARY_CONSTRUCTOR)
        // An explicit constructor has preceding annotations, modifiers, or is on a separate line from the class name
        val precedingNode = getPrecedingLeadingCommentsAndWhitespaces()
        return precedingNode != this
    }", "new_string": "    private fun ASTNode.hasExplicitConstructorKeyword(): Boolean {
        require(elementType == PRIMARY_CONSTRUCTOR)

        // Check if there are modifiers or annotations that would make the constructor keyword explicit
        val modifierList = parent(CLASS)?.findChildByType(MODIFIER_LIST)
        if (modifierList != null && modifierList.children().any { it.elementType == ANNOTATION_ENTRY }) {
            return true
        }

        // Check if constructor is preceded by whitespace/comments that would indicate it's on a separate line
        val precedingNode = getPrecedingLeadingCommentsAndWhitespaces()
        return precedingNode != this && precedingNode.textContains('\n')
    }"}

