        require(elementType == PRIMARY_CONSTRUCTOR)

        // A constructor is explicit if:
        // 1. It has annotations or modifiers preceding it (forcing explicit constructor keyword)
        // 2. It appears on a separate line from the class name (explicit constructor keyword)

        val classNode = parent(CLASS) ?: return false

        // Check for annotations on the constructor 
        val precedingNode = getPrecedingLeadingCommentsAndWhitespaces()
        if (precedingNode != this) {
            // If there are annotations or modifiers before the constructor, it's explicit
            val textBetween = classNode.text.substring(
                classNode.textRange.startOffset,
                this.textRange.startOffset
            )
            if (textBetween.contains("@") || textBetween.contains("constructor")) {
                return true
            }
            // If constructor is on a separate line, it's explicit
            if (precedingNode.textContains('\n')) {
                return true  
            }
        }

        return false
    }"}

